@app.route('/saml/login')
def saml_login():
    """Initiate SAML authentication by redirecting to IdP."""
    request_id, authn_request_xml = create_authn_request()

    # Store request ID in session for InResponseTo validation
    session['saml_request_id'] = request_id
    session['saml_request_time'] = datetime.utcnow().isoformat()

    # Base64 encode the request
    encoded_request = base64.b64encode(authn_request_xml.encode('utf-8')).decode('utf-8')

    # For HTTP-Redirect binding, we'd URL-encode and redirect
    # For HTTP-POST binding, we render a form that auto-submits
    return render_template_string("""
    <!DOCTYPE html>
    <html>
    <head><title>Redirecting to Identity Provider...</title></head>
    <body onload="document.getElementById('saml-form').submit();">
        <p>Redirecting to Identity Provider for authentication...</p>
        <form id="saml-form" method="POST" action="{{ idp_sso_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <input type="hidden" name="RelayState" value="{{ relay_state }}" />
            <noscript>
                <p>JavaScript is disabled. Please click the button below to continue.</p>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    """, idp_sso_url=SAML_CONFIG['idp_sso_url'],
         saml_request=encoded_request,
         relay_state=session.get('next_url', url_for('dashboard')))


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - Process SAML response from IdP."""
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', url_for('dashboard'))

    if not saml_response_b64:
        return jsonify({'error': 'No SAMLResponse found in the request'}), 400

    try:
        parser = SAMLResponseParser(saml_response_b64)
    except Exception as e:
        return jsonify({'error': f'Failed to parse SAML response: {str(e)}'}), 400

    # Get stored request ID for InResponseTo validation
    expected_request_id = session.pop('saml_request_id', None)
    session.pop('saml_request_time', None)

    # Parse and validate the response
    is_valid = parser.parse_and_validate(expected_request_id=expected_request_id)

    if not is_valid:
        return render_template_string("""
        <!DOCTYPE html>
        <html>
        <head><title>SSO Authentication Failed</title></head>
        <body>
            <h1>Authentication Failed</h1>
            <p>The SAML response validation failed with the following errors:</p>
            <ul>
            {% for error in errors %}
                <li>{{ error }}</li>
            {% endfor %}
            </ul>
            <a href="{{ url_for('saml_login') }}">Try Again</a>
        </body>
        </html>
        """, errors=parser.errors), 403

    # Extract user data
    user_data = parser.get_user_data()

    # Create user session
    session.permanent = True
    session['user'] = {
        'name_id': user_data.get('name_id'),
        'email': user_data.get('email', user_data.get('name_id')),
        'first_name': user_data.get('first_name', ''),
        'last_name': user_data.get('last_name', ''),
        'display_name': user_data.get('display_name', ''),
        'groups': user_data.get('groups', []),
        'roles': user_data.get('roles', []),
        'uid': user_data.get('uid', ''),
        'session_index': user_data.get('session_index'),
        'authenticated_at': datetime.utcnow().isoformat(),
        'attributes': user_data.get('attributes', {}),
    }

    # Remove next_url from session
    session.pop('next_url', None)

    return redirect(relay_state)


@app.route('/saml/sls', methods=['GET', 'POST'])
def saml_sls():
    """Single Logout Service - Handle logout requests/responses from IdP."""
    if request.method == 'POST':
        saml_response_b64 = request.form.get('SAMLResponse')
        saml_request_b64 = request.form.get('SAMLRequest')
    else:
        saml_response_b64 = request.args.get('SAMLResponse')
        saml_request_b64 = request.args.get('SAMLRequest')

    if saml_response_b64:
        # IdP is responding to our logout request
        try:
            raw = base64.b64decode(saml_response_b64)
            root = ET.fromstring(raw.decode('utf-8'))
            status = root.find('.//samlp:Status/samlp:StatusCode', SAML_NAMESPACES)
            if status is not None:
                status_value = status.get('Value', '')
                if status_value == 'urn:oasis:names:tc:SAML:2.0:status:Success':
                    session.clear()
                    return redirect(url_for('index'))
        except Exception:
            pass

        session.clear()
        return redirect(url_for('index'))

    elif saml_request_b64:
        # IdP is requesting us to logout (IdP-initiated logout)
        try:
            raw = base64.b64decode(saml_request_b64)
            root = ET.fromstring(raw.decode('utf-8'))
            request_id = root.get('ID', '')

            # Clear the session
            session.clear()

            # Send LogoutResponse back to IdP
            response_id = f'_id-{uuid.uuid4()}'
            issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

            logout_response = f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:LogoutResponse
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{response_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_slo_url']}"
    InResponseTo="{request_id}">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
</samlp:LogoutResponse>"""

            encoded_response = base64.b64encode(logout_response.encode('utf-8')).decode('utf-8')

            return render_template_string("""
            <!DOCTYPE html>
            <html>
            <head><title>Logging out...</title></head>
            <body onload="document.getElementById('slo-form').submit();">
                <form id="slo-form" method="POST" action="{{ idp_slo_url }}">
                    <input type="hidden" name="SAMLResponse" value="{{ saml_response }}" />
                    <noscript>
                        <input type="submit" value="Continue Logout" />
                    </noscript>
                </form>
            </body>
            </html>
            """, idp_slo_url=SAML_CONFIG['idp_slo_url'],
                 saml_response=encoded_response)

        except Exception as e:
            session.clear()
            return redirect(url_for('index'))

    session.clear()
    return redirect(url_for('index'))


@app.route('/saml/logout')
@login_required
def saml_logout():
    """Initiate SAML Single Logout."""
    user = session.get('user', {})
    name_id = user.get('name_id', '')
    session_index = user.get('session_index', '')

    if not name_id:
        session.clear()
        return redirect(url_for('index'))

    request_id, logout_request_xml = create_logout_request(name_id, session_index)
    session['saml_logout_request_id'] = request_id

    encoded_request = base64.b64encode(logout_request_xml.encode('utf-8')).decode('utf-8')

    return render_template_string("""
    <!DOCTYPE html>
    <html>
    <head><title>Logging out...</title></head>
    <body onload="document.getElementById('slo-form').submit();">
        <p>Logging out...</p>
        <form id="slo-form" method="POST" action="{{ idp_slo_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <noscript>
                <input type="submit" value="Continue Logout" />
            </noscript>
        </form>
    </body>
    </html>
    """, idp_slo_url=SAML_CONFIG['idp_slo_url'],
         saml_request=encoded_request)


